// ---------------------------------------------------------------------------
// Dangerous / disallowed operators and keys that must be stripped or rejected
// ---------------------------------------------------------------------------
const DISALLOWED_OPERATORS = new Set([
  '$where',       // Allows arbitrary JS execution on the server
  '$accumulator', // Allows arbitrary JS in aggregation
  '$function',    // Allows arbitrary JS in aggregation
]);

// Fields that must never appear in a projection (i.e., must always be excluded)
const SENSITIVE_FIELDS = new Set([
  'password',
  'passwordHash',
  'secret',
  'token',
  'refreshToken',
  'ssn',
  'creditCard',
]);

// Maximum number of documents that can be returned in a single query
const MAX_LIMIT = 500;
const DEFAULT_LIMIT = 50;

// Maximum depth we allow in a filter object to prevent abuse
const MAX_FILTER_DEPTH = 6;

// ---------------------------------------------------------------------------
// Sanitization helpers
// ---------------------------------------------------------------------------

/**
 * Recursively walk an object and:
 *  1. Remove any keys that are in the DISALLOWED_OPERATORS set.
 *  2. Ensure $regex values are strings (prevent ReDoS with length cap).
 *  3. Enforce a maximum nesting depth.
 *
 * Throws if the object is too deeply nested or contains outright dangerous content.
 */
function sanitizeFilter(obj, depth = 0) {
  if (depth > MAX_FILTER_DEPTH) {
    throw new Error(`Filter object exceeds maximum allowed depth of ${MAX_FILTER_DEPTH}`);
  }

  if (obj === null || obj === undefined) {
    return obj;
  }

  // Primitives are safe
  if (typeof obj !== 'object') {
    return obj;
  }

  // Arrays – recurse into each element
  if (Array.isArray(obj)) {
    return obj.map((item) => sanitizeFilter(item, depth + 1));
  }

  const sanitized = {};

  for (const [key, value] of Object.entries(obj)) {
    // 1. Block disallowed operators
    if (DISALLOWED_OPERATORS.has(key)) {
      console.warn(`Blocked disallowed operator "${key}" in query filter`);
      continue; // silently strip
    }

    // 2. Sanitize $regex values
    if (key === '$regex') {
      if (typeof value !== 'string') {
        throw new Error('$regex value must be a string');
      }
      if (value.length > 200) {
        throw new Error('$regex value exceeds maximum allowed length of 200 characters');
      }
      sanitized[key] = value;
      continue;
    }

    // 3. Prevent prototype-pollution style keys
    if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
      continue;
    }

    // Recurse
    sanitized[key] = sanitizeFilter(value, depth + 1);
  }

  return sanitized;
}

/**
 * Ensure the projection never exposes sensitive fields.
 * If the caller explicitly includes sensitive fields (value 1), strip them.
 * If the caller explicitly excludes them (value 0), keep that exclusion.
 * We also forcibly add exclusion for every sensitive field.
 */
function sanitizeProjection(projection) {
  if (!projection || typeof projection !== 'object' || Array.isArray(projection)) {
    // Return a default projection that hides sensitive fields
    const defaults = {};
    for (const field of SENSITIVE_FIELDS) {
      defaults[field] = 0;
    }
    return defaults;
  }

  const sanitized = {};

  // Determine if the caller is using inclusion or exclusion mode
  const values = Object.values(projection);
  const isInclusion = values.some((v) => v === 1 || v === true);

  for (const [key, value] of Object.entries(projection)) {
    if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
      continue;
    }
    // In inclusion mode, strip sensitive fields even if caller requests them
    if (isInclusion && SENSITIVE_FIELDS.has(key)) {
      continue;
    }
    sanitized[key] = value;
  }

  // In exclusion mode (or mixed), ensure sensitive fields are always excluded
  if (!isInclusion) {
    for (const field of SENSITIVE_FIELDS) {
      sanitized[field] = 0;
    }
  }

  return sanitized;
}

/**
 * Sanitize sort specification – only allow 1 / -1 values and cap the number
 * of sort keys to prevent abuse.
 */
function sanitizeSort(sort) {
  if (!sort || typeof sort !== 'object' || Array.isArray(sort)) {
    return undefined;
  }

  const MAX_SORT_KEYS = 5;
  const sanitized = {};
  let count = 0;

  for (const [key, value] of Object.entries(sort)) {
    if (count >= MAX_SORT_KEYS) break;
    if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
      continue;
    }
    const numVal = Number(value);
    if (numVal !== 1 && numVal !== -1) {
      continue; // skip invalid sort directions
    }
    sanitized[key] = numVal;
    count++;
  }

  return Object.keys(sanitized).length > 0 ? sanitized : undefined;
}

