/**
 * queryBuilder – builds and executes a MongoDB find() with sanitized inputs.
 *
 * @param {string}  collectionName  – the MongoDB collection to query
 * @param {object}  filter          – MongoDB query filter (operators allowed except dangerous ones)
 * @param {object}  [projection]    – field inclusion/exclusion spec
 * @param {object}  [sort]          – sort specification e.g. { createdAt: -1 }
 * @param {number}  [limit]         – max documents to return (capped at MAX_LIMIT)
 * @param {number}  [skip]          – number of documents to skip (pagination)
 * @returns {Promise<{ data: Array, total: number, limit: number, skip: number }>}
 */
async function queryBuilder(collectionName, filter = {}, projection = null, sort = null, limit = DEFAULT_LIMIT, skip = 0) {
  // --- Validate collection name ---
  if (typeof collectionName !== 'string' || !/^[a-zA-Z_][a-zA-Z0-9_]{0,63}$/.test(collectionName)) {
    throw new Error('Invalid collection name');
  }

  // --- Sanitize all inputs ---
  const safeFilter = sanitizeFilter(filter);
  const safeProjection = sanitizeProjection(projection);
  const safeSort = sanitizeSort(sort);

  // --- Clamp limit and skip ---
  let safeLimit = parseInt(limit, 10);
  if (isNaN(safeLimit) || safeLimit < 1) safeLimit = DEFAULT_LIMIT;
  if (safeLimit > MAX_LIMIT) safeLimit = MAX_LIMIT;

  let safeSkip = parseInt(skip, 10);
  if (isNaN(safeSkip) || safeSkip < 0) safeSkip = 0;

  // --- Execute query ---
  const collection = db.collection(collectionName);

  const [data, total] = await Promise.all([
    collection
      .find(safeFilter, { projection: safeProjection })
      .sort(safeSort || {})
      .skip(safeSkip)
      .limit(safeLimit)
      .toArray(),
    collection.countDocuments(safeFilter),
  ]);

  return {
    data,
    total,
    limit: safeLimit,
    skip: safeSkip,
  };
}

